type User struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
}

func main() {
	http.HandleFunc("/users/", searchUsersHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}

func searchUsersHandler(w http.ResponseWriter, r *http.Request) {
	username := r.URL.Query().Get("username")
	if username == "" {
		http.Error(w, "Username is required", http.StatusBadRequest)
		return
	}

	const (
		connStr = "user=your_user dbname=your_db password=your_password host=localhost sslmode=disable"
	)

	db, err := sql.Open("postgres", connStr)
	if err != nil {
		log.Fatalf("failed opening connection: %v", err)
	}
	defer db.Close()

	rows, err := db.Query("SELECT id, username FROM users WHERE username = $1", username)
	if err != nil {
		log.Fatalf("failed querying database: %v", err)
	}
	defer rows.Close()

	var users []User
	for rows.Next() {
		var user User
		err = rows.Scan(&user.ID, &user.Username)
		if err != nil {
			log.Fatalf("failed scanning row: %v", err)
		}
		users = append(users, user)
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(users)
}